var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지가 보스였을 때는 사업하기 참 좋은 시절이었어.","JPN":"父がボスだった頃はちょうど事業がうまくいっていた時期だった。","ENG":"When my father was the Don, it was easy to do business.","TWN":"父親當老闆的時候，正是事業上升期。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"전쟁으로 생긴 건설 호황, 치안 공백, 용병업이 흥하면서 활발해진 무기 밀거래......","JPN":"戦争後の建設好況、治安の悪化、傭兵業が盛んで活発になった武器密売……","ENG":"The war left us with a construction boom, weak law enforcement, and mercenaries who needed black market weapons...","TWN":"戰爭產生的建設繁榮、治安不佳、傭兵業興盛，還有盛行的武器走私……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"전부 아버지의 든든한 비즈니스 파트너였지.","JPN":"ある意味、すべてが父のビジネスパートナーだった。","ENG":"Everyone was a solid business partner for my father back then.","TWN":"全部都是父親可靠的商業夥伴。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"문제는 아무리 꼼꼼하게 바른 벽지도, 시간이 지나면 언젠가 닳아 떨어진다는 거야.","JPN":"問題はいくら念入りに張った壁紙でも、時間が経つにつれ劣化して剝がれ落ちるってこと。","ENG":"The trouble is, even the sturdiest castle wears down and crumbles with time.","TWN":"但問題是，無論多麼認真仔細貼上的壁紙，隨著時間的推移，總有一天也是會磨損掉落的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아르세니코 패밀리는...... 다른 것들보다 조금 더 빨랐어.","JPN":"アルセニコファミリーには……他の連中よりその時が早く来てしまった。","ENG":"As for the Arsenicos... that time came sooner than most.","TWN":"阿塞妮克家族……相對來說速度更快一些。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"범인은 아직 못 찾았답니까?","JPN":"犯人はまだ見つかってないんですか？","ENG":"They haven't found the culprit yet?","TWN":"犯人還沒有抓到嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"경찰들도 뚜렷한 단서가 없다고 하더라.","JPN":"警察も明確な手がかりがないと言っていた。","ENG":"Even the police said they didn't have any clear leads.","TWN":"員警也說沒有明確的線索。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"냉정하게 생각해, 리타. 사고일 가능성도 고민해 봐야지.","JPN":"冷静に考えろ、リタ。事故の可能性も考えないと。","ENG":"You've got to be clear-eyed about this sort of stuff, Rita. There's always the possibility that it was an accident.","TWN":"麗塔，你冷靜想一想，也可能就只是意外呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"숙부님이야말로 냉정해지시죠.","JPN":"叔父さんこそ、冷静になってください。","ENG":"You're the one who should clear your eyes, uncle.","TWN":"叔父您才應該冷靜吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"확률이 0인 가능성을 고민하는 건 시간 낭비일 뿐입니다.","JPN":"確率が0の可能性を悩むのは時間の無駄です。","ENG":"It's a waste of time considering the possibility of the improbable.","TWN":"思考一件可能性為零的事情不過是浪費時間而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"차 밑에서 뭔가가 폭발했습니다. 숙부님.","JPN":"車の下で何かが爆発したのです。","ENG":"Something blew up under the car. Uncle.","TWN":"車底好像有什麼東西爆炸了，叔父。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"다른 곳도 아니고, 아르세니코 패밀리의 보스가 앉아 있던 좌석 바로 밑에서.","JPN":"他の場所ではなく、アルセニコファミリーのボスが座っていた座席のすぐ下で。","ENG":"Right under the Arsenicos' boss, no less.","TWN":"不是其他地方，就在阿塞妮克家族老大的座椅下面。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저한테는 가스관이 폭발했다는 추측보다 누군가 차 밑에 폭발물을 심어 뒀다는 쪽이 더 설득력 있게 느껴지는군요.","JPN":"私にはガス管が爆発したという推測よりも、誰かが車の下に爆発物を仕組んだという話が一番説得力があると思います。","ENG":"To me, the possibility of someone planting explosives under the car seems a lot more plausible than this gas pipe explosion theory.","TWN":"在我看來，比起排氣管道爆炸的推測，更有可能是有人在車底安裝了爆炸物。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"네가 예민하게 굴 만한 일이라는 건 나도 알아. 그래도......","JPN":"君が敏感になっても仕方ないことは私も理解している。それでも……","ENG":"I completely understand why you'd be so touchy about this. Still...","TWN":"我知道你對這件事非常敏感。但是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 병상만 봐도 그렇습니다.","JPN":"この病室もそうです。","ENG":"Look around you.","TWN":"看看這個病床。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지 몸에 생채기만 나도 호들갑 떨던 자들이 얼굴 한 번 안 비추지 않습니까.","JPN":"父の体にできたちょっとした傷でも大げさに騒いでいた者たちが、一度も顔を出さないなんて。","ENG":"All those goons who'd flip out over a scratch on father's body... where are they now?","TWN":"那些以前只要父親受了一點點傷就大呼小叫的人，現在連影子都找不到了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"크흠......","JPN":"コホン……","ENG":"Ahem...","TWN":"咳咳……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"성냥팔이는 뭐라고 변명하던가요?","JPN":"マッチ売りはなんて言い訳していましたか？","ENG":"What did the Matchmaker say?","TWN":"賣火柴組織是怎麼說的？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"......지부장이라면 며칠째 연락이 안 돼.","JPN":"……支部長なら数日連絡が取れない。","ENG":"No one's been able to reach the Capo for days now.","TWN":"……分公司主管已經好幾天都聯繫不上了。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지가 거두지 않았으면 길거리에서 객사했을 싸움꾼 주제에......","JPN":"父に引き取ってもらえなかったら、その辺で野垂れ死んでもおかしくないチンピラだったくせに……","ENG":"That brawler would have died on the street long ago if father hadn't taken him in...","TWN":"如果沒有父親收留，那些人都已經客死街頭了，現在……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이유야 어쨌든 그 놈 구역에서 일어난 불상사입니다.","JPN":"理由はともかく、奴の区域で起こった不祥事です。","ENG":"In any case, this happened on his turf.","TWN":"不管怎樣，這件事都是發生在那個傢伙的地盤上。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"지부장으로서 책임지고 수습해야 하는 거 아닙니까?","JPN":"支部長として責任持って解決するのは当然ではありませんか？","ENG":"Shouldn't he take responsibility for this as the Capo in charge?","TWN":"作為分公司主管，不應該負責解決嗎？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"리타, 암살자 색출보다 더 급한 문제가 있어.","JPN":"リタ、暗殺者探しよりもっと急がねばならない問題がある。","ENG":"Rita, there's a more urgent matter than finding the culprit.","TWN":"麗塔，有比搜捕暗殺者更緊迫的問題。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"평의회에 자금을 약속한 날짜가 바로 오늘이야.","JPN":"評議会に資金を約束した期日が今日だ。","ENG":"The payment we promised the Council is due today.","TWN":"跟評議會約款的日子就是今天。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"자정이 지나면 그걸 빌미로 우리 조직을 박살낼 거다.","JPN":"午前0時を過ぎたら、それを口実に我々の組織を破壊するだろう。","ENG":"If we don't pay by midnight, they'll use that as the excuse to tear the Family apart.","TWN":"過了午夜，就會以那個為藉口毀掉我們的組織。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"자금은 어떻게든 조달할 겁니다. 아르세니코 패밀리는 약속을 어기지 않아요.","JPN":"資金は何とか調達します。アルセニコファミリーは約束を守ります。","ENG":"We'll get the money, no matter what. The Arsenicos always honors its promise.","TWN":"資金一定會籌措到。阿塞妮克家族絕不會違背約定。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"대체 무슨 수로? 산하 조직들도 평의회 눈치를 살피느라 전부 관망하는데?","JPN":"いったいどうやって？　傘下組織も評議会の顔色をうかがって皆様子見しかしてないぞ。","ENG":"But how? Nobody's stepping up to help us in case they upset the Council.","TWN":"能有什麼辦法？連旗下組織也在採取觀望態度，都在看評議會的臉色呢？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그럼 숙부님은 뾰족한 수라도 있습니까?","JPN":"では叔父さんは何か手があるんですか？","ENG":"Then do you have any better ideas, uncle?","TWN":"那麼叔父您有什麼辦法嗎？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"평의회가...... 내게 언질을 주더구나.","JPN":"評議会が……私に提案をしてくれた。","ENG":"The Council... gave me a notice.","TWN":"評議會……已經給我暗示了。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"네가 가진 능력으로 자기들 사업에 협력한다면, 날짜를 연기해 주겠다고.","JPN":"君が持っている能力で自分たちの事業に協力するなら、期日を延期すると。","ENG":"They said they'd postpone the due date if you use your powers to help with their business.","TWN":"如果你用你的能力協助他們的事業，就幫我們延期。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"그뿐만이 아니야.","JPN":"それだけではない。","ENG":"That's not all.","TWN":"不只如此。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"형님이 저 지경이 되고 나서 다른 조직들에게 빼앗긴 사업장들도 되찾게 도와 준다더구나.","JPN":"兄貴があのような状況になってから、他の組織に奪われた事業所も取り戻せるように助力してくれると言った。","ENG":"They even said they'll help us get back the businesses we lost to other families after the boss went down.","TWN":"據說還能幫忙收回大哥倒下之後被其他組織搶走的場子。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꽤 매력적인 제안이군요.","JPN":"かなり魅力的な提案ですね。","ENG":"That's a very appealing offer.","TWN":"真是個不錯的提議。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"제가 그것들 조폐기로 쓰이는 동안 숙부님이 차기 보스가 될 미래까지 감안하면 더더욱 말이죠.","JPN":"私が彼らに造幣機械扱いされている間、叔父が次期ボスになる未来まで考えれば、尚更です。","ENG":"Especially for you, considering how you'll be taking over as the Don while I work my butt off as their living ATM.","TWN":"我成為他們的印鈔機，同時也為叔父你成為BOSS鋪路，真是太好了是吧。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"리타, 말이 너무 심하지 않니.","JPN":"リタ、言い過ぎとは思わないか？","ENG":"That's a bit out of the line, Rita.","TWN":"麗塔，你這話說得太過分了吧。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"제가 너무 정곡을 찔렀습니까?","JPN":"あまりにも図星でしたか？","ENG":"Or maybe I've hit the nail on the head?","TWN":"是我正中要害了吧？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"제안에 대한 대답을 말씀 드리겠습니다. 평의회에 한 글자도 빠짐없이 전해 주시죠.","JPN":"提案への返事を申し上げます。評議会には一言も漏れなくお伝えください。","ENG":"Here's my response to their offer. Please make sure you pass it on, verbatim.","TWN":"我現在答覆您。請您一字不少的轉達給評議會。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"약속했던 자금은 넘겨 주겠다. 하지만 제안은 거절하지.","JPN":"約束した資金は渡してやる。しかし提案は断る。","ENG":"We'll give you the money, as promised. But we refuse the other offer.","TWN":"我會把承諾的資金給他們，但我拒絕那個提議。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지가 깨어나 공증인이 되어 주시지 않는 한, 너희들과 다음 약속 따위는 없다.","JPN":"父が目覚めて公証人にならない限り、お前らと次の約束などない。","ENG":"I'll never make a deal with you unless father comes back and vouches for you personally.","TWN":"除非父親醒過來做公證人，跟你們不會再有什麼瓜葛。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"아니, 타협하면 될 일을 가지고 왜 어려운 길을 가려는 거냐?","JPN":"妥協すれば解決するのに、なぜ厳しい道を進もうとするのだ？","ENG":"Why do you insist on doing things the hard way?","TWN":"哎呀，你只要妥協一下就可以了，何必自找苦吃呢？"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지는 아르세니코 패밀리가 선을 넘지 않길 바라셨습니다.","JPN":"父はアルセニコファミリーが一線を越えないようにしていました。","ENG":"Father never wanted the Arsenicos to cross the line.","TWN":"父親希望阿塞妮克家族不要越界。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"약속의 무게도 모르는 승냥이들에게 굴복하는 건 아버지께서 원하시던 바가 아니에요.","JPN":"約束の重さも知らない狡猾な連中に屈服するのは、父の意向に反することです。","ENG":"He'd never want the family to capitulate to a bunch of treacherous wolves.","TWN":"父親不會希望我向那些不懂得承諾之重的豺狼屈服的。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"리타. 나도 정말 이렇게까지 하긴 원치 않았어.","JPN":"リタ。私だって本当は、ここまでしたくなかった。","ENG":"Rita. I really didn't want to go this far.","TWN":"麗塔，我真的不想走到這一步。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"기계수집가의 부하들이군요. 평의회가 던져주는 먹이가 꽤나 마음에 든 모양입니다.","JPN":"機械収集家の部下ですか。評議会が投げてくれた餌がかなり気に入ったようですね。","ENG":"These are the Machine Collector's goons. You must be quite pleased with the Council's offer.","TWN":"原來是機械收藏家的部下啊。看來對評議會扔給你的食物你很滿意啊。"},"stage":{"bg":"MANSION","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"형님도 너도, 너무 낡았어.","JPN":"兄貴も君も、頭が固すぎるのだ。","ENG":"Both you and the boss are far too outdated.","TWN":"大哥和你，兩個都太固執了。"},"stage":{"bg":"MANSION","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"나도 오랫동안 조직에 헌신해 왔다. 그걸 너희 부녀가 망치는 꼴은 더 두고 볼 수가 없구나.","JPN":"私も長きにわたり組織に貢献してきた。お前たち親子が台無しにするのをこれ以上看過できない。","ENG":"I've dedicated myself to the Family for many years as well. I can't bear to watch you and your old man ruin it any longer.","TWN":"我也一直為了組織而奉獻了我的全部。不能眼睜睜看著你們父女倆毀了這個組織。"},"stage":{"bg":"MANSION","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"다시 생각해 봐라. 간부들 중에도 이미 나와 같은 뜻을 가진 이들이 대다수야.","JPN":"もう一度考え直せ。幹部もすでに私と同じ意思を持っている者が過半数だ。","ENG":"Think about it again. A vast majority of the Capos share my feelings.","TWN":"再考慮考慮吧。目前幹部中跟我想法一致的人可是占大多數。"},"stage":{"bg":"MANSION","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"당연히 그렇겠죠. 반대자들은 모두 자기 차 밑에서 뭔가가 터졌을 테니까.","JPN":"当然そうでしょうね。反対する者は全員自分の車の下で何かが爆発したはずですから。","ENG":"I bet they do. Anyone who objected probably had something blow up under their cars.","TWN":"這真是廢話。因為持反對意見的人，看來車底肯定也爆炸了吧。"},"stage":{"bg":"MANSION","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래도 듣던 중 반가운 소립니다, 숙부님. 저희 사이에 처음으로 공감대가 형성됐군요.","JPN":"でも、ある意味では嬉しいです、叔父さん。私も叔父さんと同じことを考えました。","ENG":"Well, I'm glad to hear of this, uncle. This is the first time you and I agree on something.","TWN":"不過我聽你這麼說還挺開心的，叔父。我們之間第一次有了共識。"},"stage":{"bg":"MANSION","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"......나도 당신 같은 배신자가 설치는 꼴은 두고 볼 수가 없거든.","JPN":"……私もお前のような裏切り者が調子に乗っている様をこれ以上見逃せないからな。","ENG":"I can't stand the sight of a backstabbing fool like you either.","TWN":"……我也無法忍受像你這樣的叛徒在組織裡為所欲為。"},"stage":{"bg":"MANSION","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"}]`);export{e as default};